// Coleta os dados do nó $('MergePendente') e do nó $('If')
const dadosRequerente = $node["dadosRequerente"].json;
const validacaoWhatsApp = $node["If1"].json;

// Função para determinar a saudação com base no horário atual
function obterSaudacao() {
  const hora = new Date().getHours();
  if (hora >= 6 && hora < 12) {
    return "Bom dia";
  } else if (hora >= 12 && hora < 18) {
    return "Boa tarde";
  } else {
    return "Boa noite";
  }
}

// Verifica se há dados do requerente e da validação do WhatsApp
if (dadosRequerente && validacaoWhatsApp) {
  const requerente = dadosRequerente; // Dados do requerente
  const whatsappValido = validacaoWhatsApp.exists;
  const jid = validacaoWhatsApp.jid;
  const numero = validacaoWhatsApp.number;

  if (!whatsappValido) {
    const saudacao = obterSaudacao(); // Obtém a saudação adequada

    // Cria a mensagem informando que o número não possui WhatsApp, incluindo jid
    const mensagem = `${saudacao}!\n\n` +
      `O número telefônico ${numero} do requerente ${requerente.nomeRquerente} não possui WhatsApp.\n\n`;

    // Retorna a mensagem formatada como string JSON
    return {
      textMessage: {
        msg: JSON.stringify(mensagem.trim())
      }
    };
  } else {
    // Caso o número possua WhatsApp, retorna uma mensagem informativa
    return {
      textMessage: {
        msg: JSON.stringify("O número telefônico possui WhatsApp.")
      }
    };
  }
} else {
  // Retorna uma mensagem padrão caso não haja dados suficientes
  return {
    textMessage: {
      msg: JSON.stringify("Não foram encontrados dados para validação do WhatsApp.")
    }
  };
}

